def parse_subparser_arguments(unparsed_arguments, subparsers):
    """
    给定一个参数序列和一个从子解析器名称到 argparse.ArgumentParser 实例的字典，让每个请求的操作的子解析器尝试解析所有参数。这允许共享常见参数（例如 --repository）给多个子解析器。

    将结果作为一个元组返回，其中包含一个将子解析器名称映射到其解析后的 argparse.Namespace 实例的字典和一个包含未被任何子解析器认领的剩余参数的列表。
    """
    remaining_args = unparsed_arguments[:]
    parsed_results = {}

    for name, parser in subparsers.items():
        try:
            # Try to parse the arguments for the current subparser
            parsed_args, remaining_args = parser.parse_known_args(remaining_args)
            parsed_results[name] = parsed_args
        except SystemExit:
            # Handle the case where parsing fails
            continue

    return parsed_results, remaining_args

from typing import List, Optional

def int_to_string(number: int, alphabet: List[str], padding: Optional[int] = None) -> str:
    if number < 0:
        raise ValueError("Number must be non-negative")

    base = len(alphabet)
    if base < 2:
        raise ValueError("Alphabet must contain at least two characters")

    result = []
    while number > 0:
        result.append(alphabet[number % base])
        number //= base

    result.reverse()
    result_str = ''.join(result)

    if padding is not None:
        result_str = result_str.zfill(padding)

    return result_str

from typing import Optional, Set
from rdflib import Graph, URIRef

def find_roots(
    graph: Graph, prop: URIRef, roots: Optional[Set["Node"]] = None
) -> Set["Node"]:
    if roots is None:
        roots = set()

    all_nodes = set(graph.subjects(prop, None))
    child_nodes = set(graph.objects(None, prop))

    for node in all_nodes:
        if node not in child_nodes:
            roots.add(node)

    return roots

def load_configurations(config_filenames, overrides=None, resolve_env=True):
    import logging
    import os
    import json

    logger = logging.getLogger(__name__)
    error_records = []
    config_dict = {}

    for filename in config_filenames:
        try:
            if not os.path.isfile(filename):
                raise FileNotFoundError(f"Configuration file {filename} not found.")

            with open(filename, 'r') as file:
                config = json.load(file)

            if overrides:
                config.update(overrides)

            if resolve_env:
                for key, value in config.items():
                    if isinstance(value, str) and value.startswith('$'):
                        env_var = value[1:]
                        config[key] = os.getenv(env_var, value)

            config_dict[filename] = config

        except Exception as e:
            log_record = logger.error(f"Error loading configuration file {filename}: {e}")
            error_records.append(log_record)

    return config_dict, error_records

def protocol_handlers(cls, protocol_version=None):
    """
    返回一个可用的 Bolt 协议处理程序的字典，以版本元组为键。如果提供了明确的协议版本，字典将包含零个或一个条目，具体取决于该版本是否受支持。如果未提供协议版本，将返回所有可用的版本。

    :param protocol_version: 标识特定协议版本的元组（例如 (3, 5)）或 None
    :return: 一个字典，键为版本元组，值为所有相关且受支持的协议版本的处理程序类
    :raise TypeError: 如果协议版本未以元组形式传入
    """
    if protocol_version is not None and not isinstance(protocol_version, tuple):
        raise TypeError("协议版本必须是一个元组")

    # 假设我们有一个字典，存储所有支持的协议版本和对应的处理程序类
    supported_protocols = {
        (3, 0): 'HandlerFor3_0',
        (3, 5): 'HandlerFor3_5',
        (4, 0): 'HandlerFor4_0',
    }

    if protocol_version is not None:
        return {protocol_version: supported_protocols.get(protocol_version)} if protocol_version in supported_protocols else {}

    return supported_protocols

def from_raw_values(cls, values):
    """
    从一组原始书签字符串值创建一个 Bookmarks 对象。

    除非您需要反序列化书签，否则不需要使用此方法。

    :param values: ASCII 字符串值（原始书签）
    :type values: Iterable[str]
    """
    bookmarks = []
    for value in values:
        if isinstance(value, str):
            bookmarks.append(value)
    return cls(bookmarks)

