def fromutc(self, dt):
    """
    给定一个在给定时区中带有时区信息的日期时间对象，计算在新时区的带有时区信息的日期时间。

    由于这是我们*明确知道*日期时间对象没有歧义的唯一时刻，我们利用这个机会来判断该日期时间是否存在歧义，并且是否处于“折叠”状态（例如，如果这是歧义日期时间的第一个按时间顺序出现的实例）。

    :param dt: 一个带有时区信息的 :class:`datetime.datetime` 对象。
    """
    # 检查输入的日期时间对象是否带有时区信息
    if dt.tzinfo is None:
        raise ValueError("dt must be a timezone-aware datetime object")

    # 将输入的日期时间转换为 UTC
    utc_dt = dt.astimezone(self.utc)

    # 计算在新时区的日期时间
    new_dt = utc_dt.astimezone(self)

    # 检查是否存在歧义
    if new_dt.dst() != timedelta(0):
        # 处理歧义情况
        if new_dt < self._fold_start:
            return new_dt.replace(tzinfo=self, fold=0)
        else:
            return new_dt.replace(tzinfo=self, fold=1)

    return new_dt.replace(tzinfo=self)

def identify_request(request: RequestType):
    """
    检查通过 JSON 加载的请求体是否包含事件。如果包含，则返回真；否则，检查从请求体加载的 XML 的标签是否为 Magic_ENV_TAG，如果是，则返回真。如果上述条件均不满足，则返回假。

    尝试识别这是否是一个 Diaspora 请求。

    首先尝试检查是否为公共消息，然后检查是否为私有消息。最后检查这是否是旧式（Legacy）负载。
    """
    # 假设 request 是一个字典，包含 JSON 和 XML 数据
    if 'json' in request:
        json_data = request['json']
        if 'event' in json_data:
            return True

    if 'xml' in request:
        xml_data = request['xml']
        if xml_data.tag == 'Magic_ENV_TAG':
            return True

    return False

def format_dt(dt):
    """
    使用 `ensure_timezone` 函数格式化 `dt` 的时间并返回时间。

    以 D* 节点期望的方式格式化日期时间。
    """
    from datetime import datetime
    import pytz

    def ensure_timezone(dt):
        if dt.tzinfo is None:
            return dt.replace(tzinfo=pytz.UTC)
        return dt.astimezone(pytz.UTC)

    dt_with_tz = ensure_timezone(dt)
    return dt_with_tz.strftime('%Y-%m-%d %H:%M:%S %Z')

import requests
from typing import Optional

def fetch_content_type(url: str) -> Optional[str]:
    """
    通过 URL 和 USER_AGENT 设置请求的头部。

    通过获取远程 URL 的 HEAD 请求来确定内容类型。
    """
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/58.0.3029.110 Safari/537.3'
    }

    try:
        response = requests.head(url, headers=headers)
        response.raise_for_status()  # Raise an error for bad responses
        return response.headers.get('Content-Type')
    except requests.RequestException:
        return None

def xml_children_as_dict(node):
    """
    将 <xml> 节点的子节点转换为一个字典，以标签名称作为键。

    这只是一个浅层转换——子节点不会被递归处理。
    """
    return {child.tag: child for child in node}

from typing import Dict
import json
import xml.etree.ElementTree as ET

def parse_diaspora_webfinger(document: str) -> Dict:
    """
    通过读取 JSON 格式的文档获取 Webfinger，Webfinger 中的 `hcard_url` 值是文档中 `links` 的 `href` 值。

    解析 Diaspora 的 Webfinger，该 Webfinger 可以是 JSON 格式（新格式）或 XRD 格式（旧格式）。

    https://diaspora.github.io/diaspora_federation/discovery/webfinger.html
    """
    try:
        # Try to parse as JSON
        data = json.loads(document)
        if 'links' in data:
            for link in data['links']:
                if 'rel' in link and link['rel'] == 'http://webfinger.net/rel/hcard':
                    return {'hcard_url': link['href']}
    except json.JSONDecodeError:
        pass

    try:
        # Try to parse as XML (XRD format)
        root = ET.fromstring(document)
        for link in root.findall('{http://docs.oasis-open.org/ns/xri/xrd-1.0}Link'):
            rel = link.get('rel')
            if rel == 'http://webfinger.net/rel/hcard':
                return {'hcard_url': link.get('href')}
    except ET.ParseError:
        pass

    return {}

