def get_deprecated_args(self):
    """
    返回一个包含会弃用其他选项的字典。选项来自 `self.spec_helper.iterate_option_specs()`。
    返回一个包含会弃用其他选项的字典。
    """
    deprecated_args = {}
    for option in self.spec_helper.iterate_option_specs():
        if option.get('deprecated', False):
            deprecated_args[option['name']] = option['replacement']
    return deprecated_args

def validate_arg_deprecation(self, cli_args, answer_file_args):
    """
    验证并打印已弃用的参数。

    :param cli_args: 来自命令行的参数字典
    :param answer_file_args: 来自文件的参数字典
    """
    deprecated_args = set(cli_args.keys()).intersection(set(answer_file_args.keys()))

    if deprecated_args:
        print("已弃用的参数:")
        for arg in deprecated_args:
            print(f"- {arg}")
    else:
        print("没有已弃用的参数。")

def get_nested_custom_and_control_args(self, args):
    """
    将输入参数分为控制，嵌套和自定义参数。

    控制参数：用于控制中间表示的行为。这些参数不会被写入到规范yml文件中。  
    嵌套参数：用于Ansible playbooks，并会被写入到规范yml文件中。  
    自定义参数：自定义的Ansible变量，用于替代常规的嵌套参数使用。

    :param args: 收集到的参数列表。
    :return: (dict, dict): 扁平化的字典（control_args, nested_args）
    """
    control_args = {}
    nested_args = {}

    for key, value in args.items():
        if key.startswith('control_'):
            control_args[key] = value
        elif key.startswith('nested_'):
            nested_args[key] = value
        else:
            # Assuming custom args are those that don't fit the above categories
            nested_args[key] = value

    return control_args, nested_args

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    使用 ``extra-vars`` 扩展 ``vars_dict``。

    :param vars_dict: 要合并 extra-vars 的字典
    :param extra_vars: extra-vars的列表
    """
    if extra_vars is None:
        return vars_dict

    for var in extra_vars:
        if isinstance(var, dict):
            vars_dict.update(var)
        else:
            raise ValueError("extra_vars should be a list of dictionaries.")

    return vars_dict

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    通过修改 values_dict 参数将参数转换为正确的类型。

    默认情况下，所有的值都是字符串。

    :param parser_name: 命令名称，例如 main、virsh、ospd 等
    :param values_dict: 包含参数的字典
    """
    for key, value in values_dict.items():
        if value.isdigit():
            values_dict[key] = int(value)
        else:
            try:
                # Attempt to convert to float if it's not an integer
                values_dict[key] = float(value)
            except ValueError:
                # Keep it as a string if it can't be converted
                values_dict[key] = value

import os
import yaml

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    使用 YAML 来读取 `plugin_dir` 中的各种信息，并以字典形式将其返回。
    从插件规范创建一个扁平化的字典

    :param plugin_dir: 插件目录的路径
    :return: 一个包含插件属性的扁平化字典
    """
    flatten_dict = {}

    for root, _, files in os.walk(plugin_dir):
        for file in files:
            if file.endswith('.yaml') or file.endswith('.yml'):
                file_path = os.path.join(root, file)
                with open(file_path, 'r', encoding='utf-8') as f:
                    try:
                        content = yaml.safe_load(f)
                        if isinstance(content, dict):
                            for key, value in content.items():
                                flatten_dict[key] = value
                    except yaml.YAMLError as e:
                        print(f"Error reading {file_path}: {e}")

    return flatten_dict
